kernel_src="""

#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;
constexpr float NEG_INF = -1e38f;

class KernelLogSoftmaxCustom {
public:
    __aicore__ inline KernelLogSoftmaxCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalLength, uint32_t featureSize,
                                uint32_t tileLength, int32_t dim)
    {
        totalLen_ = totalLength;
        featureSize_ = featureSize;
        tileLen_ = tileLength;
        dim_ = dim;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);

        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue1_, 1, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue2_, 1, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue3_, 1, sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (totalLen_ == 0 || tileLen_ == 0) return;

        uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
        uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());
        uint32_t rows = totalLen_ / featureSize_;

        for (uint32_t row = blockIdx; row < rows; row += blockNum) {
            uint32_t rowBase = row * featureSize_;
            float rowMax = NEG_INF;

            // Pass 1: compute max over row
            uint32_t offset = 0;
            while (offset < featureSize_) {
                uint32_t curLen = (offset + tileLen_ <= featureSize_) ? tileLen_ : (featureSize_ - offset);
                if (curLen == 0) break;

                // Load tile
                AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
                AscendC::DataCopy(xLocal, xGm_[rowBase + offset], curLen);
                inQueueX_.EnQue(xLocal);
                xLocal = inQueueX_.DeQue<float>();

                // Manual max over tile elements
                float tileMax = NEG_INF;
                for (uint32_t i = 0; i < curLen; ++i) {
                    float val = xLocal(i);
                    if (val > tileMax) tileMax = val;
                }
                if (tileMax > rowMax) rowMax = tileMax;

                inQueueX_.FreeTensor(xLocal);
                offset += curLen;
            }

            // Pass 2: compute sum of exp(x - rowMax)
            float rowSumExp = 0.0f;
            offset = 0;
            while (offset < featureSize_) {
                uint32_t curLen = (offset + tileLen_ <= featureSize_) ? tileLen_ : (featureSize_ - offset);
                if (curLen == 0) break;

                AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
                AscendC::DataCopy(xLocal, xGm_[rowBase + offset], curLen);
                inQueueX_.EnQue(xLocal);
                xLocal = inQueueX_.DeQue<float>();

                // y = x - rowMax (scalar subtraction using a temporary tensor)
                AscendC::LocalTensor<float> tmp = tmpQueue1_.AllocTensor<float>();
                AscendC::Dup(tmp, rowMax, curLen);
                AscendC::Sub(tmp, xLocal, tmp, curLen); // tmp = x - rowMax
                AscendC::Exp(tmp, tmp, curLen); // exp(tmp)

                // Manual sum over tile
                float tileSum = 0.0f;
                for (uint32_t i = 0; i < curLen; ++i) {
                    tileSum += tmp(i);
                }
                rowSumExp += tileSum;

                tmpQueue1_.FreeTensor(tmp);
                inQueueX_.FreeTensor(xLocal);
                offset += curLen;
            }

            // logSum = log(rowSumExp)
            float logSum;
            {
                AscendC::LocalTensor<float> logScalar = tmpQueue3_.AllocTensor<float>();
                AscendC::Dup(logScalar, rowSumExp, 1);
                AscendC::Log(logScalar, logScalar, 1);
                logSum = logScalar.GetValue(0);
                tmpQueue3_.FreeTensor(logScalar);
            }

            // Pass 3: compute output y = x - rowMax - logSum
            offset = 0;
            while (offset < featureSize_) {
                uint32_t curLen = (offset + tileLen_ <= featureSize_) ? tileLen_ : (featureSize_ - offset);
                if (curLen == 0) break;

                AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
                AscendC::DataCopy(xLocal, xGm_[rowBase + offset], curLen);
                inQueueX_.EnQue(xLocal);
                xLocal = inQueueX_.DeQue<float>();

                AscendC::LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();

                // y = x - rowMax
                AscendC::LocalTensor<float> tmp = tmpQueue2_.AllocTensor<float>();
                AscendC::Dup(tmp, rowMax, curLen);
                AscendC::Sub(yLocal, xLocal, tmp, curLen);
                // y = y - logSum
                AscendC::Dup(tmp, logSum, curLen);
                AscendC::Sub(yLocal, yLocal, tmp, curLen);

                tmpQueue2_.FreeTensor(tmp);
                inQueueX_.FreeTensor(xLocal);

                outQueueY_.EnQue<float>(yLocal);
                yLocal = outQueueY_.DeQue<float>();
                AscendC::DataCopy(yGm_[rowBase + offset], yLocal, curLen);
                outQueueY_.FreeTensor(yLocal);
                offset += curLen;
            }
        }
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpQueue1_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpQueue2_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpQueue3_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t totalLen_ {0};
    uint32_t featureSize_ {0};
    uint32_t tileLen_ {0};
    int32_t dim_ {1};
};

extern "C" __global__ __aicore__ void log_softmax_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelLogSoftmaxCustom op;
    op.Init(x, y, tiling_data.totalLength, tiling_data.featureSize,
            tiling_data.tileLength, tiling_data.dim);
    op.Process();
}
